import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

const Register = () => {
  const [formData, setFormData] = useState({
    full_name: '',
    email: '',
    registration_number: '',
    password: '',
    confirmPassword: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      alert("Passwords do not match!");
      return;
    }

    try {
      const response = await axios.post('http://localhost:5000/api/users/register', {
        full_name: formData.full_name,
        email: formData.email,
        registration_number: formData.registration_number,
        password: formData.password
      });

      if (response.status === 201) {
        alert("Registration Successful!");
        navigate('/login'); // Redirect to login page
      }
    } catch (error) {
      alert(error.response?.data?.error || "Registration failed");
    }
  };

  return (
    <div className="bg-[#f0f4f8] min-h-screen font-display flex flex-col">
      <header className="flex items-center justify-between border-b border-slate-300 bg-white px-6 md:px-10 py-4">
        <div className="flex items-center gap-3">
          <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-[#137fec] text-white">
            <span className="material-symbols-outlined text-xl">school</span>
          </div>
          <h2 className="text-black text-lg font-bold tracking-tight">UniEvents</h2>
        </div>
      </header>

      <main className="flex-grow flex items-center justify-center px-4 py-12">
        <div className="w-full max-w-md bg-white rounded-2xl shadow-2xl overflow-hidden border border-slate-200">
          <div className="p-10">
            <div className="text-center mb-8">
              <h1 className="text-3xl font-black text-slate-900">Create Account</h1>
            </div>

            <form className="space-y-4" onSubmit={handleRegister}>
              <input name="full_name" onChange={handleChange} className="w-full p-3 bg-[#f0f4f8] rounded-xl outline-none" placeholder="Full Name" required />
              <input name="email" type="email" onChange={handleChange} className="w-full p-3 bg-[#f0f4f8] rounded-xl outline-none" placeholder="University Email" required />
              <input name="registration_number" onChange={handleChange} className="w-full p-3 bg-[#f0f4f8] rounded-xl outline-none" placeholder="Registration Number" required />
              
              <div className="relative">
                <input 
                  name="password" 
                  type={showPassword ? "text" : "password"} 
                  onChange={handleChange} 
                  className="w-full p-3 bg-[#f0f4f8] rounded-xl outline-none" 
                  placeholder="Password" 
                  required 
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400">
                  <span className="material-symbols-outlined">{showPassword ? "visibility_off" : "visibility"}</span>
                </button>
              </div>

              <input name="confirmPassword" type="password" onChange={handleChange} className="w-full p-3 bg-[#f0f4f8] rounded-xl outline-none" placeholder="Confirm Password" required />

              <button className="w-full bg-[#137fec] text-white font-bold py-4 rounded-xl shadow-lg mt-4" type="submit">
                Register
              </button>
            </form>
          </div>
        </div>
      </main>
    </div>
  );
};

export default Register;
